import subprocess, json, tempfile, os

VERSION_PATHS = {
    '2022': 'C:/Program Files/Autodesk/Maya2022/bin/mayapy.exe',
    '2024': 'C:/Program Files/Autodesk/Maya2024/bin/mayapy.exe',
    '2025': 'C:/Program Files/Autodesk/Maya2025/bin/mayapy.exe',
    '2026': 'C:/Program Files/Autodesk/Maya2026/bin/mayapy.exe',
}

MAYA_RUNNER_SCRIPT = '''import json, sys, os
import maya.cmds as cmds
import maya.standalone
maya.standalone.initialize()

with open(sys.argv[1], "r") as f:
    payload = json.load(f)

results_path = sys.argv[2]
results = {"actions": [], "errors": []}

scene_file = payload.get("scene_file", "")
if scene_file:
    try:
        cmds.file(scene_file, open=True, force=True)
    except Exception as e:
        results["errors"].append("Failed to open scene: " + str(e))
        with open(results_path, "w") as f:
            json.dump(results, f)
        cmds.quit(force=True)
        sys.exit(1)

for i, action in enumerate(payload.get("actions", [])):
    action_type = action.get("type", "")
    entry = {"index": i, "type": action_type, "ok": False, "error": ""}
    try:
        if action_type == "open_scene":
            cmds.file(action["scene_path"], open=True, force=action.get("force", True))
            entry["ok"] = True
        elif action_type == "import_obj":
            cmds.file(action["obj_path"], i=True, type="OBJ", ignoreVersion=True)
            entry["ok"] = True
        elif action_type == "save_scene":
            cmds.file(rename=action["save_scene_path"])
            cmds.file(save=True, type=action.get("file_type", "mayaAscii"))
            entry["ok"] = True
        elif action_type == "reference_alembic":
            cmds.loadPlugin("AbcImport", quiet=True)
            cmds.file(action["abc_path"], reference=True, type="Alembic", ignoreVersion=True, namespace=action.get("namespace", "abc_ref"))
            entry["ok"] = True
        elif action_type == "custom_python":
            user_code = action.get("python_code", "")
            exec(user_code, {"cmds": cmds, "action": action, "os": os, "json": json})
            entry["ok"] = True
        else:
            entry["error"] = "unknown action type"
    except Exception as e:
        entry["error"] = str(e)
    results["actions"].append(entry)

with open(results_path, "w") as f:
    json.dump(results, f)

cmds.quit(force=True)
'''

def _parse_maya_env(path):
    """Parse a Maya.env file into a dict of env vars."""
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            if '=' in line:
                key, val = line.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _parse_bat_env(path):
    """Parse SET commands from a .bat file into a dict of env vars."""
    env = {}
    if not path or not os.path.isfile(path):
        return env
    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            lower = line.lower()
            if lower.startswith('set ') and '=' in line:
                rest = line[4:]
                key, val = rest.split('=', 1)
                env[key.strip()] = val.strip()
    return env

def _build_env(bat_file, maya_env_file):
    """Merge current env with bat and Maya.env vars. bat takes precedence over Maya.env."""
    env = os.environ.copy()
    maya_vars = _parse_maya_env(maya_env_file)
    bat_vars = _parse_bat_env(bat_file)
    # Maya.env first, then bat overrides
    for k, v in maya_vars.items():
        # Expand references to existing env vars like %PYTHONPATH%
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    for k, v in bat_vars.items():
        for ek, ev in env.items():
            v = v.replace(f'%{ek}%', ev)
        env[k] = v
    return env

async def on_parameter_changed(self, name, value):
    if name == 'maya_version' and value in VERSION_PATHS:
        self.set_parameter('mayapy.exe', VERSION_PATHS[value])

def _fail(self, msg):
    return {'success': False, 'stdout': '', 'stderr': msg, 'exit_code': -1, 'executed_actions': [], 'skipped_actions': []}

async def _set_outputs(self, result):
    for k, v in result.items():
        await self.set_output(k, v)
    await self.set_output('exec_out', True)

async def execute(self, inputs):
    version = inputs.get('maya_version') or self.get_parameter('maya_version', '2024')
    mayapy = inputs.get('mayapy.exe') or self.get_parameter('mayapy.exe', '')
    if not mayapy and version in VERSION_PATHS:
        mayapy = VERSION_PATHS[version]
    bat_file = inputs.get('bat_file') or self.get_parameter('bat_file', '')
    maya_env_file = inputs.get('maya_env_file') or self.get_parameter('maya_env_file', '')
    scene_file = inputs.get('scene_file') or self.get_parameter('scene_file', '')
    actions = inputs.get('actions') or []

    if not isinstance(actions, list):
        actions = [actions]

    # Build environment from bat and Maya.env
    env = _build_env(bat_file, maya_env_file)
    env_sources = []
    if bat_file:
        env_sources.append(f'bat: {bat_file}')
    if maya_env_file:
        env_sources.append(f'Maya.env: {maya_env_file}')
    if env_sources:
        self.log_info(f'Environment loaded from: {" + ".join(env_sources)}')

    # Validate actions upfront
    planned = []
    skipped = []
    for action in actions:
        if not isinstance(action, dict):
            skipped.append({'action': action, 'reason': 'not a dict'})
            continue
        action_type = action.get('type', '')
        if action_type == 'open_scene':
            if not action.get('scene_path'):
                skipped.append({'action': action, 'reason': 'scene_path is empty'})
                continue
            planned.append(action)
        elif action_type == 'import_obj':
            if not action.get('obj_path'):
                skipped.append({'action': action, 'reason': 'obj_path is empty'})
                continue
            planned.append(action)
        elif action_type == 'save_scene':
            if not action.get('save_scene_path'):
                skipped.append({'action': action, 'reason': 'save_scene_path is required'})
                continue
            planned.append(action)
        elif action_type == 'reference_alembic':
            if not action.get('abc_path'):
                skipped.append({'action': action, 'reason': 'abc_path is empty'})
                continue
            planned.append(action)
        elif action_type == 'custom_python':
            if not action.get('python_code'):
                skipped.append({'action': action, 'reason': 'python_code is empty'})
                continue
            planned.append(action)
        else:
            skipped.append({'action': action, 'reason': f'unknown action type: {action_type}'})

    if skipped:
        for s in skipped:
            self.log_error(f'Action skipped: {s["reason"]}')
        result = _fail(self, f'{len(skipped)} action(s) skipped due to validation errors')
        result['skipped_actions'] = skipped
        await _set_outputs(self, result)
        return result

    # Write structured payload and results file
    payload = {'scene_file': scene_file, 'actions': planned}
    payload_file = tempfile.NamedTemporaryFile(mode='w', suffix='.json', delete=False)
    script_file = tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False)
    results_file = tempfile.NamedTemporaryFile(mode='w', suffix='_results.json', delete=False)
    results_file.close()
    try:
        json.dump(payload, payload_file)
        payload_file.close()
        script_file.write(MAYA_RUNNER_SCRIPT)
        script_file.close()

        cmd = [mayapy, script_file.name, payload_file.name, results_file.name]
        self.log_info(f'Running Maya {version}: {" ".join(cmd)}')

        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=600, env=env)

        # Parse structured results from Maya
        executed = []
        maya_errors = []
        try:
            with open(results_file.name, 'r') as rf:
                maya_results = json.load(rf)
            for ar in maya_results.get('actions', []):
                if ar.get('ok'):
                    executed.append(planned[ar['index']])
                else:
                    maya_errors.append(f'Action {ar["index"]} ({ar["type"]}): {ar["error"]}')
            maya_errors.extend(maya_results.get('errors', []))
        except Exception:
            pass

        has_stderr_errors = False
        if proc.stderr:
            for line in proc.stderr.splitlines():
                if line.strip().startswith('Error:') or line.strip().startswith('RuntimeError:'):
                    has_stderr_errors = True
                    break

        ok = proc.returncode == 0 and not maya_errors and not has_stderr_errors
        if not ok and not maya_errors and has_stderr_errors:
            maya_errors.append('Maya reported errors in stderr (exit code was 0)')

        for err in maya_errors:
            self.log_error(err)

        result = {
            'success': ok,
            'stdout': proc.stdout,
            'stderr': proc.stderr,
            'exit_code': proc.returncode,
            'executed_actions': executed,
            'skipped_actions': [],
        }
        await _set_outputs(self, result)

        if ok:
            self.log_info(f'Maya completed successfully. {len(executed)} actions executed.')
        else:
            self.log_error(f'Maya run failed. {len(executed)}/{len(planned)} actions succeeded.')

        return result
    except Exception as e:
        self.log_error(f'Maya execution failed: {e}')
        result = _fail(self, str(e))
        await _set_outputs(self, result)
        return result
    finally:
        for f in [payload_file.name, script_file.name, results_file.name]:
            try:
                os.unlink(f)
            except Exception:
                pass
